records = [
  {"id":"inno_ent_301","name_ja":"起業家精神の測定指標体系","name_en":"Measurement Systems for Entrepreneurship","definition":"起業活動を定量化するために開発された各種指標体系の研究。OECD/Eurostat起業家統計フレームワーク（EIP）、World Bank Doing Business指標、GEM TEA、GEDI（Global Entrepreneurship and Development Index）等が主要測定ツール。企業開廃業率、生存率、雇用創出力、ハイグロース企業比率（ガゼル）が標準的アウトカム指標として用いられる。","impact_summary":"起業活動の多次元的測定を可能にし、国際比較研究と政策評価の共通基盤を整備した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"実証的起業家研究","era_start":2008,"schumpeter_layer":"メゾ","innovation_type":"測定・指標イノベーション","cognitive_mechanism":"指標設計と政策フィードバックループ","key_researchers":["Zoltan Acs","Laszlo Szerb","Niels Bosma"],"key_works":["GEDI Index (2011)","Measuring Entrepreneurship (OECD 2008)"],"keywords_ja":"起業測定,GEDI,TEA,GEM,ガゼル企業","keywords_en":"entrepreneurship measurement,GEDI,TEA,GEM,gazelle firms"},
  {"id":"inno_ent_302","name_ja":"ガゼル企業と高成長スタートアップ","name_en":"Gazelle Firms and High-Growth Startups","definition":"Birch（1979）が命名した高成長企業（ガゼル）の研究。3年以上連続して年20%以上の成長率を示す企業をガゼルと定義し、雇用創出の大部分は少数の高成長企業から生まれることを実証した。OECD定義（10人以上の企業が3年以上20%超成長）が国際比較基準。ガゼルの出現確率を高める制度・政策・エコシステム要因が研究される。","impact_summary":"「スモールビジネスではなくハイグロース企業が雇用創出の担い手」という政策転換を促す実証的基盤を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"実証的起業家研究","era_start":1979,"schumpeter_layer":"ミクロ","innovation_type":"成長イノベーション","cognitive_mechanism":"成長志向と市場機会の同時充足","key_researchers":["David Birch","Erik Hurst","Benjamin Pugsley"],"key_works":["The Job Generation Process (1979)","The Aggregate Implications of Entrepreneurship (2011)"],"keywords_ja":"ガゼル企業,高成長スタートアップ,雇用創出,Birch","keywords_en":"gazelle firms,high-growth startups,job creation,Birch"},
  {"id":"inno_ent_303","name_ja":"起業家精神の心理的特性研究","name_en":"Psychological Traits of Entrepreneurs","definition":"起業家の心理的特性を実証する研究の蓄積。達成動機（McClelland 1961）、内的統制信念（Rotter）、リスク許容度、曖昧さへの耐性、自己効力感（Bandura）が主要測定概念。Big Five性格特性（特に誠実性・外向性・経験開放性）と起業成果の関係も研究される。特定の心理的プロファイルが起業成功を予測するかの「特性論」批判も存在する。","impact_summary":"起業家の心理的プロフィールを特定する試みとして多くの研究を生み出し、起業家育成プログラムの設計に影響した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"認知的起業家論","era_start":1961,"schumpeter_layer":"ミクロ","innovation_type":"心理・行動研究","cognitive_mechanism":"達成動機と自己効力感の起業行動への変換","key_researchers":["David McClelland","Julian Rotter","Albert Bandura"],"key_works":["The Achieving Society (1961)","Social Foundations of Thought and Action (1986)"],"keywords_ja":"起業家の心理特性,達成動機,内的統制,自己効力感","keywords_en":"entrepreneurial traits,achievement motivation,locus of control,self-efficacy"},
  {"id":"inno_ent_304","name_ja":"起業家精神とネットワーク構造","name_en":"Network Structure and Entrepreneurship","definition":"社会ネットワーク分析（SNA）を起業家研究に応用した研究。起業家のネットワーク中心性、密度、多様性が機会認識・資源調達・パフォーマンスに与える影響が実証される。Hite & Hesterly（2001）は新興企業がネットワーク構造を「identity-based」から「calculative-based」へ移行するプロセスを分析した。LinkedIn等のデジタルネットワークの影響も研究される。","impact_summary":"ネットワーク構造が起業家の機会と資源へのアクセスを規定することを実証し、スタートアップのネットワーキング戦略設計に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"ネットワーク論的起業家論","era_start":2001,"schumpeter_layer":"ミクロ","innovation_type":"ネットワークイノベーション","cognitive_mechanism":"ネットワーク媒介型機会認識と資源動員","key_researchers":["Julia Hite","William Hesterly","Howard Aldrich"],"key_works":["The Evolution of Firm Networks (2001)","Organizations Evolving (1999)"],"keywords_ja":"ネットワーク,SNA,起業家,機会認識,資源調達","keywords_en":"network,SNA,entrepreneurship,opportunity recognition,resource mobilization"},
  {"id":"inno_ent_305","name_ja":"シュンペーターの動的起業家像","name_en":"Schumpeter's Dynamic Entrepreneur","definition":"Schumpeter（1911/1934）が提唱した起業家像：新結合（neue Kombinationen）を実行する「創造的破壊者」。生産要素の新たな組み合わせ（新製品・新生産方法・新市場・新原料供給源・新組織形態の5類型）を実現する起業家が経済発展の原動力となる。晩年の「Mark II」では大企業R&D部門が起業家機能を担うと修正した。","impact_summary":"現代イノベーション研究の出発点として、起業家を経済変化の主要エージェントとして位置づける理論的基盤を確立した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"シュンペーター派","era_start":1911,"schumpeter_layer":"マクロ","innovation_type":"理論的イノベーション","cognitive_mechanism":"新結合の認識と実行への意志","key_researchers":["Joseph Schumpeter","Erik Reinert","Giovanni Dosi"],"key_works":["Theorie der wirtschaftlichen Entwicklung (1911)","The Theory of Economic Development (1934)"],"keywords_ja":"シュンペーター,新結合,創造的破壊,起業家,経済発展","keywords_en":"Schumpeter,new combinations,creative destruction,entrepreneur,economic development"},
  {"id":"inno_ent_306","name_ja":"Kirznerの警覚性理論","name_en":"Kirzner's Alertness Theory","definition":"Israel Kirzner（1973）が提唱した起業家的警覚性（entrepreneurial alertness）理論。市場の不均衡（価格差・需給ギャップ）に気づく「警覚性」が起業家の本質的特性であり、これが市場均衡化プロセスを駆動するとした。Schumpeterの「均衡破壊的」起業家像と対比される「均衡回復的」起業家像を提示した。オーストリア学派の市場過程論の延長線上にある。","impact_summary":"機会認識の認知的・主観的側面を強調し、起業家的機会研究の主要な対抗枠組みの一つを提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"オーストリア学派","era_start":1973,"schumpeter_layer":"ミクロ","innovation_type":"理論的イノベーション","cognitive_mechanism":"市場不均衡の警覚的認識と均衡回復行動","key_researchers":["Israel Kirzner","Friedrich Hayek","Peter Klein"],"key_works":["Competition and Entrepreneurship (1973)","The Meaning of Market Process (1992)"],"keywords_ja":"Kirzner,警覚性,市場均衡,オーストリア学派,機会認識","keywords_en":"Kirzner,alertness,market equilibrium,Austrian school,opportunity recognition"},
  {"id":"inno_ent_307","name_ja":"ブリコラージュとスタートアップ","name_en":"Bricolage in Startups","definition":"Baker & Nelson（2005）が起業家研究に導入したブリコラージュ概念：「手近にあるものを創造的に組み合わせて新しいものを作る」実践。資源制約の強い環境（農村、発展途上国、ソーシャルベンチャー）での起業行動を説明する。物理的ブリコラージュ（有形資源の転用）・制度的ブリコラージュ（慣行の組み合わせ）・社会的ブリコラージュ（ネットワーク活用）の3類型が識別される。","impact_summary":"「資源制約を創造性で超える」起業家行動の理論化に成功し、BootstrappingやLeanスタートアップの理論的基盤の一つとなった。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"プロセス理論","era_start":2005,"schumpeter_layer":"ミクロ","innovation_type":"資源活用イノベーション","cognitive_mechanism":"資源転用と即興的問題解決","key_researchers":["Ted Baker","Reed Nelson","Melissa Cardon"],"key_works":["Creating Something from Nothing (2005)","Entrepreneurial Bricolage (2008)"],"keywords_ja":"ブリコラージュ,資源制約,転用,即興,ブートストラップ","keywords_en":"bricolage,resource constraints,repurposing,improvisation,bootstrapping"},
  {"id":"inno_ent_308","name_ja":"ブートストラップ起業戦略","name_en":"Bootstrapping Entrepreneurship Strategy","definition":"外部資金（VC・銀行融資）に頼らず自己資金・顧客収入・クレジットカード等で事業を立ち上げ・成長させる戦略。Winborg & Landström（2001）は複数のブートストラップ手法（顧客前払い、バーター取引、中古設備利用等）を分類した。SaaS企業の「Bootstrapped Unicorn」（Mailchimp、Basecamp）が注目され、VC依存からの解放とコントロール維持を重視する起業家思想の流れを形成した。","impact_summary":"VC依存モデルへの代替的成長戦略として注目を集め、資本アクセスに制約のある起業家の選択肢を拡大した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"実践的起業家方法論","era_start":2001,"schumpeter_layer":"ミクロ","innovation_type":"財務戦略イノベーション","cognitive_mechanism":"自律性動機と収益優先経営","key_researchers":["Joakim Winborg","Hans Landström","Jason Fried"],"key_works":["Bootstrapping Strategies (2001)","ReWork (2010)"],"keywords_ja":"ブートストラップ,自己資金,Mailchimp,収益優先,VC不依存","keywords_en":"bootstrapping,self-funded,Mailchimp,revenue-first,VC-independent"},
  {"id":"inno_ent_309","name_ja":"起業家精神の神経科学的研究","name_en":"Neuroscience of Entrepreneurship","definition":"脳科学・神経科学の手法を起業家研究に応用する新興領域。Laureiro-Martínez et al.（2015）はfMRIを使い起業家は探索的思考時により前頭前野を活性化することを示した。ドーパミン系との起業家的リスク選好の関係、神経可塑性と起業家的学習の関係が研究される。ニューロリーダーシップとの接続も進みつつある。","impact_summary":"起業家行動の神経生物学的基盤への理解を深め、起業家の認知・意思決定研究の生物学的次元を開拓した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"認知的起業家論","era_start":2010,"schumpeter_layer":"ミクロ","innovation_type":"研究方法論イノベーション","cognitive_mechanism":"前頭前野活性化と探索的意思決定","key_researchers":["Nicola Laureiro-Martínez","Stefano Brusoni","Francesco Canessa"],"key_works":["Understanding the Exploration-Exploitation Dilemma (2015)","Entrepreneurs vs. Managers (2014)"],"keywords_ja":"起業家精神,神経科学,fMRI,認知,ドーパミン","keywords_en":"neuroscience,entrepreneurship,fMRI,cognition,dopamine"},
  {"id":"inno_ent_310","name_ja":"家族企業の後継者育成とイノベーション","name_en":"Family Business Succession and Innovation","definition":"家族企業の事業承継プロセスと承継時のイノベーション行動の変化を研究する領域。後継者（特に2代目）が「搾取（exploitation）」重視から「探索（exploration）」への転換を図る事例が多い。日本の老舗企業（長寿企業）研究では、伝統の維持と革新の共存（「守破離」）が持続的競争優位の源泉として分析される。",  "impact_summary":"事業承継を技術革新の契機として捉える視点を提供し、老舗企業のイノベーション研究を活性化した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"家族企業論","era_start":2005,"schumpeter_layer":"ミクロ","innovation_type":"組織・世代間イノベーション","cognitive_mechanism":"後継者の正当性構築とイノベーション動機","key_researchers":["Pramodita Sharma","Jess Chua","James Chrisman"],"key_works":["Predictors of Succession in Family Firms (2003)","Family Businesses: Resilience and Innovation (2015)"],"keywords_ja":"家族企業,事業承継,老舗,守破離,2代目","keywords_en":"family business,succession,long-lived firms,innovation,second-generation"},
  {"id":"inno_ent_311","name_ja":"スタートアップのピボット戦略","name_en":"Startup Pivot Strategy","definition":"製品・市場・ビジネスモデルの根本的方向転換（ピボット）の研究。Eric Riesがリーンスタートアップで体系化したピボット類型（ズームイン、ズームアウト、顧客セグメント、顧客ニーズ、プラットフォーム、ビジネスモデル、成長エンジン、チャネル、技術ピボット等の10類型）。Instagram（写真共有へ）、Slack（ゲームからコミュニケーション）、Twitter（ポッドキャストから）が著名事例。","impact_summary":"ビジネスモデルの柔軟な変更を体系化し、不確実性下での起業家的適応行動の理論と実践を整備した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"実践的起業家方法論","era_start":2011,"schumpeter_layer":"ミクロ","innovation_type":"戦略的適応イノベーション","cognitive_mechanism":"失敗信号の認識と方向転換の意思決定","key_researchers":["Eric Ries","Steve Blank","Bob Dorf"],"key_works":["The Lean Startup (2011)","The Startup Owner's Manual (2012)"],"keywords_ja":"ピボット,方向転換,Instagram,Slack,ビジネスモデル変更","keywords_en":"pivot,strategic redirection,Instagram,Slack,business model change"},
  {"id":"inno_ent_312","name_ja":"起業家精神と文化的価値観","name_en":"Entrepreneurship and Cultural Values","definition":"Hofstede（1980）の文化次元（個人主義vs集団主義、権力格差、不確実性回避等）が起業活動に与える影響の比較研究。個人主義・低権力格差・低不確実性回避文化が高い起業率と相関することが多くの研究で確認されている。しかしシリコンバレーの集団的エコシステム（コミュニティ重視）やアジアの「関係的起業家精神」は文化的決定論への反証事例でもある。","impact_summary":"文化的価値観が起業行動を規定するメカニズムを定量化し、多文化比較起業家研究の基盤を整備した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"比較起業家論","era_start":1980,"schumpeter_layer":"メゾ","innovation_type":"文化・制度イノベーション","cognitive_mechanism":"文化的信念と起業意図の相互作用","key_researchers":["Geert Hofstede","Aldrich Howard","Friederike Welter"],"key_works":["Culture's Consequences (1980)","Contextualizing Entrepreneurship (2011)"],"keywords_ja":"起業家精神,文化,Hofstede,個人主義,不確実性回避","keywords_en":"entrepreneurship,culture,Hofstede,individualism,uncertainty avoidance"},
  {"id":"inno_ent_313","name_ja":"起業家精神教育の効果測定","name_en":"Measuring Entrepreneurship Education Effectiveness","definition":"起業家教育プログラムの効果を測定する方法論的研究。短期的アウトカム（起業意図・自己効力感の変化）と長期的アウトカム（実際の起業率・企業成長）の測定の難しさが中心課題。Randランダム化比較試験（RCT）による因果推論の試み、GEM/GALI（Global Accelerator Learning Initiative）のデータが活用される。Fayolleらの批判的レビューが方法論的厳密性を問い直した。","impact_summary":"起業家教育政策の費用対効果評価を可能にする方法論を整備し、プログラム設計改善の知見を蓄積した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"起業家教育論","era_start":2007,"schumpeter_layer":"ミクロ","innovation_type":"教育・評価イノベーション","cognitive_mechanism":"自己効力感変化と起業意図形成のメカニズム","key_researchers":["Alain Fayolle","Benoît Gailly","Narjisse Lassas-Clerc"],"key_works":["Assessing the Impact of Entrepreneurship Education (2006)","GALI Learning Report (2018)"],"keywords_ja":"起業家教育評価,起業意図,自己効力感,RCT,GALI","keywords_en":"entrepreneurship education measurement,entrepreneurial intention,self-efficacy,RCT,GALI"},
  {"id":"inno_ent_314","name_ja":"スタートアップの失敗統計と生存分析","name_en":"Startup Failure Statistics and Survival Analysis","definition":"スタートアップの生存率・廃業率とその決定要因の実証研究。典型的に設立後5年で約50%、10年で約65%が廃業する（国・産業・設立年代により異なる）。CB Insights「Top 20 Reasons Startups Fail」、Kauffman Foundationデータが主要参照。製品市場適合の欠如（42%）、資金不足（29%）、チーム問題（23%）が上位3要因。生存分析（ハザードモデル）が方法論的標準。","impact_summary":"スタートアップ失敗の体系的分析により、起業支援の優先介入ポイントを特定し、リスク管理教育に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"実証的起業家研究","era_start":2000,"schumpeter_layer":"ミクロ","innovation_type":"実証的分析イノベーション","cognitive_mechanism":"失敗要因の体系的学習と次世代への伝達","key_researchers":["Scott Shane","Paul Reynolds","Kauffman Foundation"],"key_works":["The Illusions of Entrepreneurship (2008)","CB Insights Startup Failure Report (annual)"],"keywords_ja":"スタートアップ失敗,生存率,廃業率,CB Insights,PMF不足","keywords_en":"startup failure,survival rate,mortality rate,CB Insights,PMF"},
  {"id":"inno_ent_315","name_ja":"起業家精神とレジリエンス","name_en":"Entrepreneurial Resilience","definition":"起業家の心理的・組織的回復力（レジリエンス）の研究。失敗・逆境・経済危機からの回復過程、ポジティブ適応メカニズム、精神的ハーディネス（Kobasa）が研究される。Duchek（2018）は起業家的レジリエンスを「準備（preparation）・対処（coping）・学習（learning）」の3段階プロセスとして定式化した。COVID-19危機下でのスタートアップレジリエンスが近年の主要研究テーマとなった。","impact_summary":"起業家のメンタルヘルスと回復力に関する学術的関心を高め、回復力育成プログラムの設計に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"行動的起業家論","era_start":2010,"schumpeter_layer":"ミクロ","innovation_type":"心理的・組織的回復イノベーション","cognitive_mechanism":"逆境認識・意味付け・行動再起の循環","key_researchers":["Stephanie Duchek","Johan Wiklund","Melissa Cardon"],"key_works":["Entrepreneurial Resilience (2018)","Entrepreneurial Adversity (2020)"],"keywords_ja":"起業家レジリエンス,回復力,逆境,COVID-19,精神的ハーディネス","keywords_en":"entrepreneurial resilience,recovery,adversity,COVID-19,hardiness"},
  {"id":"inno_ent_316","name_ja":"スタートアップの組織文化形成","name_en":"Startup Culture Formation","definition":"創業期から形成される組織文化の起源・発展・変容プロセスの研究。Scheinの組織文化モデル（人工物・価値観・基本的前提）の新興企業への適用。創業者の価値観が文化的DNA として組織に埋め込まれるメカニズム、急成長期のカルチャー崩壊（「成功が文化を壊す」）、採用による文化変容が研究される。Google・Amazon・Netflix等のカルチャーが研究事例として頻用される。","impact_summary":"組織文化を創業当初から意識的に設計すべき競争優位源泉として位置づけ、スタートアップのカルチャーデザイン論を整備した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"組織論的起業家論","era_start":2000,"schumpeter_layer":"ミクロ","innovation_type":"組織・文化イノベーション","cognitive_mechanism":"創業者価値観の組織的埋め込みと世代間伝達","key_researchers":["Edgar Schein","Patty McCord","Reid Hoffman"],"key_works":["Organizational Culture and Leadership (1985)","Blitzscaling (2018)"],"keywords_ja":"組織文化,創業者,カルチャーDNA,Netflix,Google","keywords_en":"organizational culture,founder,culture DNA,Netflix,Google"},
  {"id":"inno_ent_317","name_ja":"大学インキュベーターの効果研究","name_en":"University Incubator Effectiveness Research","definition":"大学付属インキュベーター（Business Incubation）の機能・効果・設計の研究。入居企業への空間・メンタリング・ネットワーク・資金アクセスの提供が標準サービス。NBIA（National Business Incubation Association）のデータによれば入居企業の5年生存率は87%（一般企業は44%）と高い。インキュベーション卒業後のサポート（バーチャルインキュベーション）や都市型インキュベーターも研究される。","impact_summary":"インキュベーターの生存率向上効果を実証し、大学発スタートアップ育成政策の重要インフラとしての地位を確立した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"エコシステム論","era_start":1985,"schumpeter_layer":"メゾ","innovation_type":"組織・インフライノベーション","cognitive_mechanism":"保護環境での学習と成長の加速","key_researchers":["David Audretsch","Sarfraz Mian","Mike Wright"],"key_works":["Business Incubation (2002)","Technology Business Incubators (1994)"],"keywords_ja":"大学インキュベーター,スタートアップ生存率,NBIA,メンタリング","keywords_en":"university incubator,startup survival rate,NBIA,mentoring"},
  {"id":"inno_ent_318","name_ja":"地方政府の起業家精神促進政策","name_en":"Local Government Entrepreneurship Promotion Policy","definition":"市区町村・都道府県レベルの地方政府による起業環境整備政策の研究。規制緩和（ワンストップ起業窓口）、スタートアップビザ、起業家支援補助金、公共調達でのスタートアップ優遇、創業スペース提供等の政策ツールが比較研究される。フィンランドのHelsinki Startup Hub、シンガポールのEnterprise Singapore、日本の福岡市「スタートアップ都市」政策が代表事例。","impact_summary":"地方政府の起業家支援政策ポートフォリオを体系化し、エコシステム形成における政府役割の再定義に貢献した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"エコシステム論","era_start":2010,"schumpeter_layer":"メゾ","innovation_type":"政策・制度イノベーション","cognitive_mechanism":"政策ツールの組み合わせと地域エコシステムへの影響","key_researchers":["Josh Lerner","Stéphane Moyson","福岡市政策研究者"],"key_works":["Boulevard of Broken Dreams (2009)","Smart Cities and Startup Ecosystems (2020)"],"keywords_ja":"地方政府,起業家支援政策,スタートアップ都市,ワンストップ窓口","keywords_en":"local government,startup policy,startup city,one-stop window"},
  {"id":"inno_ent_319","name_ja":"コワーキングスペースとエコシステム","name_en":"Co-Working Spaces and Ecosystems","definition":"WeWork、Impact Hub、Regusなどのコワーキングスペースが起業家コミュニティの形成・知識共有・偶発的出会い（serendipity）に与える影響の研究。物理的近接性と社会的交流が知識スピルオーバーを促進するメカニズムが分析される。コロナ後のハイブリッドワーク時代における「スペース＋コミュニティ」モデルの変容も研究対象。","impact_summary":"物理的空間設計が起業家エコシステム形成に与える役割を明示し、インキュベーター・アクセラレーターとの差別化を促した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"エコシステム論","era_start":2005,"schumpeter_layer":"メゾ","innovation_type":"物理的インフライノベーション","cognitive_mechanism":"近接性による偶発的知識共有","key_researchers":["Iris Merritt","Gernot Grabher","Jonas Lund"],"key_works":["Co-Working Spaces and Entrepreneurship (2017)","Third Places and Startup Culture (2019)"],"keywords_ja":"コワーキング,WeWork,Impact Hub,物理的近接性,知識共有","keywords_en":"co-working space,WeWork,Impact Hub,physical proximity,knowledge sharing"},
  {"id":"inno_ent_320","name_ja":"グローバルアクセラレーター比較研究","name_en":"Global Accelerator Comparative Research","definition":"YC、Techstars以外の世界各地のアクセラレーター（SOSV、MassChallenge、Startupbootcamp等）の比較研究。GALI（Global Accelerator Learning Initiative）による250以上のアクセラレーター横断データが主要情報源。選抜率、投資条件（エクイティvs非エクイティ）、メンター数、卒業後資金調達率の比較分析が進む。産業特化型（バイオ、農業、フィンテック）と汎用型の効果差も研究される。","impact_summary":"アクセラレーターモデルの多様性と有効性を実証的に比較し、プログラム設計の改善と起業家の選択指針を提供した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"アクセラレーター論","era_start":2013,"schumpeter_layer":"メゾ","innovation_type":"組織・支援イノベーション","cognitive_mechanism":"外部知識の集中注入と同期的コミュニティ圧力","key_researchers":["Ian Hathaway","Susan Cohen","Yael Hochberg"],"key_works":["Accelerating Startups (2013)","GALI Annual Report (2019)"],"keywords_ja":"アクセラレーター比較,GALI,MassChallenge,卒業後実績","keywords_en":"accelerator comparison,GALI,MassChallenge,post-program outcomes"},
  {"id":"inno_ent_321","name_ja":"スタートアップの国際市場参入","name_en":"Startup International Market Entry","definition":"スタートアップが海外市場に参入する際の戦略・障壁・経路の研究。Johanson & Vahlneの段階的国際化（Uppsalaモデル）がスタートアップには適合しない事例が多く、デジタル製品・API経済・クラウドインフラが参入コストを劇的に下げた。文化的距離・言語・規制の非対称性への対処戦略、ローカルパートナーシップ、政府系ランソフトサポートが研究される。","impact_summary":"デジタル時代の起業家的国際化の新しい論理を提示し、ボーングローバル研究を実務的に深化させた。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"国際起業家論","era_start":2005,"schumpeter_layer":"ミクロ","innovation_type":"国際化イノベーション","cognitive_mechanism":"デジタル媒介による参入コスト最小化","key_researchers":["Erkko Autio","Marian Jones","Oviatt & McDougall"],"key_works":["Internationalization in the Digital Age (2011)","Born Global Firms and Their International Market Entry (2015)"],"keywords_ja":"国際市場参入,ボーングローバル,デジタル国際化,文化的距離","keywords_en":"international market entry,born global,digital internationalization,cultural distance"},
  {"id":"inno_ent_322","name_ja":"政府系VC（GVC）と公的起業支援","name_en":"Government Venture Capital and Public Startup Support","definition":"政府・公的機関によるVC投資（GVC）とスタートアップ支援プログラムの効果研究。イスラエルYozmaプログラム（1993-1997、民間VC共同投資スキーム）が最成功事例として分析される。欧州投資基金（EIF）、日本政策金融公庫、韓国KVIC等が政策実施機関。公的介入の「クラウディングアウト（民間投資排除）」リスクとその回避設計が核心課題。","impact_summary":"政府のVC市場介入の最適設計を実証的に提示し、多国のベンチャーエコシステム構築政策の参照モデルを提供した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"政策的起業家論","era_start":1993,"schumpeter_layer":"メゾ","innovation_type":"政策・金融イノベーション","cognitive_mechanism":"公的補助による市場形成と民間触媒機能","key_researchers":["Josh Lerner","Saul Lerner","Yozma researchers"],"key_works":["Boulevard of Broken Dreams (2009)","Yozma Program Evaluation (2000)"],"keywords_ja":"政府系VC,Yozma,公的起業支援,クラウディングアウト","keywords_en":"government VC,Yozma,public startup support,crowding out"},
  {"id":"inno_ent_323","name_ja":"スタートアップの採用と組織設計","name_en":"Startup Hiring and Organizational Design","definition":"急成長期における組織構造の変化と人材戦略の研究。「Pizza Rule（ピザ2枚で腹一杯になれる人数がチームの最適規模）」（Jeff Bezos）等の経験則、Conwayの法則（組織構造がシステム設計を規定）のスタートアップ適用、OKR（目標と主要結果）導入のタイミングと効果が研究される。初期のジェネラリスト→専門化の移行管理が組織スケーリングの核心課題。","impact_summary":"スタートアップの組織設計を体系的に研究し、急成長時の組織崩壊防止と人材管理の実践知を整備した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"組織論的起業家論","era_start":2010,"schumpeter_layer":"ミクロ","innovation_type":"組織・人事イノベーション","cognitive_mechanism":"組織構造と情報フローの相互規定","key_researchers":["Ben Horowitz","Claire Hughes Johnson","Andy Grove"],"key_works":["The Hard Thing About Hard Things (2014)","High Output Management (1983)"],"keywords_ja":"スタートアップ採用,OKR,Conway法則,Pizza Rule,組織スケール","keywords_en":"startup hiring,OKR,Conway's law,Pizza Rule,organizational scaling"},
  {"id":"inno_ent_324","name_ja":"起業家とメンタリング関係","name_en":"Entrepreneurial Mentoring Relationships","definition":"メンターと起業家（メンティー）の関係性が起業成果に与える影響の研究。Entrepreneurial Mentoring（EM）は知識転移・ネットワーク接続・心理的支援の3機能を持つ（Sullivan 2000）。YC、Techstarsのメンター制度の効果測定、バーチャルメンタリングの有効性、多様性メンタリング（異業種・異年齢・異性）の効果が研究される。","impact_summary":"起業家メンタリングを体系的な支援手法として確立し、アクセラレーターとエコシステム設計への応用を促した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"起業家教育論","era_start":2000,"schumpeter_layer":"ミクロ","innovation_type":"人的資本・支援イノベーション","cognitive_mechanism":"経験知の非公式移転と心理的エンパワメント","key_researchers":["Robert Sullivan","Kimberly Eddleston","Michael Frese"],"key_works":["Entrepreneurial Mentoring: Reflections on What Works (2000)","Mentorship in Entrepreneurship (2013)"],"keywords_ja":"メンタリング,起業家,知識移転,YC,アクセラレーター","keywords_en":"mentoring,entrepreneurship,knowledge transfer,YC,accelerator"},
  {"id":"inno_ent_325","name_ja":"スタートアップのマーケットプレイス戦略","name_en":"Marketplace Startup Strategy","definition":"売り手と買い手を結ぶマーケットプレイス型スタートアップ（Airbnb、Uber、Etsy、Amazon Marketplace）の起業戦略研究。鶏と卵問題の解決（どちらかの側を先に構築する戦略）、マルチホーミング（複数プラットフォーム利用）防止、信頼・評判システム設計（レビュー・保険）、テイクレート（手数料率）最適化が研究される。","impact_summary":"マーケットプレイス型ビジネスモデルの経済学的・戦略的論理を整理し、プラットフォームスタートアップ投資の理解を深めた。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"プラットフォーム論","era_start":2008,"schumpeter_layer":"ミクロ","innovation_type":"プラットフォームイノベーション","cognitive_mechanism":"需給マッチングと信頼構築のメカニズム","key_researchers":["Andrei Hagiu","Simon Rothman","Andrew Chen"],"key_works":["Marketplace Businesses at Scale (2020)","Merchant of Venice (2012)"],"keywords_ja":"マーケットプレイス,Airbnb,Uber,鶏卵問題,テイクレート","keywords_en":"marketplace,Airbnb,Uber,chicken-egg,take rate"},
  {"id":"inno_ent_326","name_ja":"ハードウェアスタートアップ論","name_en":"Hardware Startup Theory","definition":"物理的製品を開発・製造・販売するハードウェアスタートアップの独自課題：NRE（Non-Recurring Engineering）費用、製造スケールアップのコスト、在庫管理、サプライチェーン構築、ハードウェアの「修正不可能性」（ソフトウェアと異なりOTAアップデートが困難な場合）。深圳エコシステム、Crowdsupply、Seeed Studio等のハードウェア特化プラットフォームが研究される。","impact_summary":"ソフトウェア偏重のスタートアップ理論の空白を埋め、物理的製品イノベーションの起業論的理解を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"技術起業家論","era_start":2012,"schumpeter_layer":"ミクロ","innovation_type":"製造技術イノベーション","cognitive_mechanism":"物理的制約と反復可能性の設計","key_researchers":["Bunnie Huang","Bolt VC team","Ben Einstein"],"key_works":["The Hardware Startup (2015)","Why Hardware is Hard (2013)"],"keywords_ja":"ハードウェアスタートアップ,NRE,製造スケール,深圳","keywords_en":"hardware startup,NRE,manufacturing scale,Shenzhen"},
  {"id":"inno_ent_327","name_ja":"スタートアップのB2Bセールス戦略","name_en":"Startup B2B Sales Strategy","definition":"企業向けソフトウェア・サービスを販売するスタートアップのセールス組織設計・プロセス最適化の研究。Aaron Rossの「Predictable Revenue」モデル（SDR＋AEの分業）がSalesforceでの実践から体系化された。エンタープライズセールスの長い意思決定サイクル、複数購買影響者（バイイングセンター）への対応、カスタマーサクセス（CS）によるネット収益維持率（NRR）管理が研究される。","impact_summary":"B2Bスタートアップのセールスオペレーションを科学化し、SaaS企業の成長エンジン設計に実践的基盤を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"スタートアップ成長論","era_start":2011,"schumpeter_layer":"ミクロ","innovation_type":"営業・販売イノベーション","cognitive_mechanism":"購買プロセスの体系化と予測可能な収益構築","key_researchers":["Aaron Ross","Jason Lemkin","Mark Roberge"],"key_works":["Predictable Revenue (2011)","The Sales Acceleration Formula (2015)"],"keywords_ja":"B2Bセールス,予測可能収益,SDR,カスタマーサクセス,NRR","keywords_en":"B2B sales,predictable revenue,SDR,customer success,NRR"},
  {"id":"inno_ent_328","name_ja":"起業家精神とイスラム金融","name_en":"Entrepreneurship and Islamic Finance","definition":"イスラム法（シャリーア）に基づく金融原則（利子禁止、リスク共有）と起業家精神の関係研究。Mudaraba（利益分配型VC）、Musharaka（共同投資）がイスラム的VCモデルとして研究される。OIC（イスラム協力機構）諸国での起業エコシステム形成、マレーシアのイスラム金融ハブ、ドバイのスタートアップエコシステムが事例。","impact_summary":"イスラム金融原則と起業資金調達を両立する制度設計を提示し、OIC諸国の起業エコシステム研究の基盤を整備した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"比較起業家論","era_start":2005,"schumpeter_layer":"メゾ","innovation_type":"金融・制度イノベーション","cognitive_mechanism":"宗教的制約下での創造的資金調達","key_researchers":["Karim Ginena","Aznan Hassan","Hossein Askari"],"key_works":["Islamic Finance (2015)","Entrepreneurship in OIC Countries (2018)"],"keywords_ja":"イスラム金融,Mudaraba,シャリーア,OIC,ドバイ","keywords_en":"Islamic finance,Mudaraba,Sharia,OIC,Dubai"},
  {"id":"inno_ent_329","name_ja":"起業家精神と不平等・包摂","name_en":"Entrepreneurship, Inequality and Inclusion","definition":"起業家精神がアクセスできる人々とできない人々の間の不平等、および起業支援政策の包摂性に関する研究。人種・ジェンダー・階級・地理による起業機会・資本アクセスの格差が実証される。Inclusive Entrepreneurship（OECD）は社会的排除されやすいグループ（長期失業者、移民、若者、高齢者、障害者）の起業支援を政策課題化した。","impact_summary":"起業家精神の包摂性問題を主流の政策議論に組み込み、起業支援の公平設計への転換を促した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"社会的起業家論","era_start":2011,"schumpeter_layer":"メゾ","innovation_type":"社会包摂イノベーション","cognitive_mechanism":"アクセス障壁の認識と包摂的設計","key_researchers":["Maura Troester","OECD team","Vivek Wadhwa"],"key_works":["Inclusive Entrepreneurship (OECD 2013)","The Immigrant Divide (2011)"],"keywords_ja":"包摂的起業家精神,不平等,アクセス格差,OECD,社会的排除","keywords_en":"inclusive entrepreneurship,inequality,access gap,OECD,social exclusion"},
  {"id":"inno_ent_330","name_ja":"新型コロナウイルスと起業家精神の変容","name_en":"COVID-19 and Entrepreneurship Transformation","definition":"COVID-19パンデミック（2020〜）が起業活動・エコシステム・資金調達に与えた影響の研究。飲食・観光・エンターテインメント領域での大規模廃業と、デジタルヘルス・リモートワーク・ECでの急成長スタートアップの二極化。SBIR/CARES等の政府緊急支援、アクセラレーターのバーチャル化、「危機における起業家精神」（crisis entrepreneurship）の研究が急増した。","impact_summary":"パンデミックが起業機会と障壁の両面を同時に生み出すことを実証し、危機対応型起業政策設計の知見を提供した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"実証的起業家研究","era_start":2020,"schumpeter_layer":"メゾ","innovation_type":"危機対応イノベーション","cognitive_mechanism":"不確実性認識と適応的ピボット行動","key_researchers":["Selin Dilli","Niels Bosma","Ethan Mollick"],"key_works":["Entrepreneurship in Times of Crisis (2020)","COVID-19 and the Future of Startups (2021)"],"keywords_ja":"COVID-19,危機起業家精神,リモートVC,パンデミック,二極化","keywords_en":"COVID-19,crisis entrepreneurship,remote VC,pandemic,polarization"},
  {"id":"inno_ent_331","name_ja":"コーポレートイノベーション戦略","name_en":"Corporate Innovation Strategy","definition":"既存大企業が起業家的革新能力を維持・再構築するための戦略的手法の研究。Horizon 1-2-3フレームワーク（McKinsey）によるイノベーション投資配分、Innovation Portfolio管理、スカンクワーク（skunkworks）プロジェクト設計が研究される。Amazon、Google、3Mの「20%ルール」等の制度設計事例が分析され、大企業のイノベーション文化形成が主要テーマ。","impact_summary":"大企業が起業家的活力を保持・再獲得するための実践的フレームワークを整備し、コーポレートイノベーション管理論を確立した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"コーポレートベンチャリング論","era_start":1995,"schumpeter_layer":"メゾ","innovation_type":"コーポレートイノベーション","cognitive_mechanism":"制度的創造性支援と組織的インセンティブ設計","key_researchers":["Clayton Christensen","Scott Anthony","Rita McGrath"],"key_works":["The Innovator's Dilemma (1997)","Seeing Around Corners (2019)"],"keywords_ja":"コーポレートイノベーション,Horizon 3,スカンクワーク,20%ルール","keywords_en":"corporate innovation,Horizon 3,skunkworks,20% rule"},
  {"id":"inno_ent_332","name_ja":"マイクロファイナンスと起業家精神","name_en":"Microfinance and Entrepreneurship","definition":"Muhammad YunusのGrameen Bank（1983年）に始まるマイクロファイナンス（小額融資）が貧困層起業家の起業行動に与える影響の研究。RCTによる実証（Banerjee et al. 2015）ではマイクロファイナンスの消費平滑化効果は確認されたが起業への変革的効果は限定的という結論も出ており、「マイクロファイナンス神話」への批判的検討が進んでいる。","impact_summary":"貧困と起業家精神の関係を実証的に検討し、マイクロファイナンス政策の有効性と限界に関する証拠基盤を整備した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"社会的起業家論","era_start":1983,"schumpeter_layer":"ミクロ","innovation_type":"金融包摂イノベーション","cognitive_mechanism":"資金アクセスと起業行動への限定的因果","key_researchers":["Muhammad Yunus","Abhijit Banerjee","Esther Duflo"],"key_works":["Banker to the Poor (1999)","The Miracle of Microfinance? (2015)"],"keywords_ja":"マイクロファイナンス,Grameen Bank,貧困起業家,金融包摂,RCT","keywords_en":"microfinance,Grameen Bank,poverty entrepreneurship,financial inclusion,RCT"},
  {"id":"inno_ent_333","name_ja":"スタートアップのデータ駆動意思決定","name_en":"Data-Driven Decision Making in Startups","definition":"分析ツール（Google Analytics、Mixpanel、Amplitude等）を活用した定量的意思決定文化とその構築プロセスの研究。A/Bテスト・コホート分析・ファネル分析・LTVモデリングがスタートアップの標準的手法として定着した経緯、データ文化の組織的埋め込み、「データを見すぎて判断を遅らせる（analysis paralysis）」問題も研究される。","impact_summary":"スタートアップ経営の科学化を促進し、製品・マーケティング・営業の意思決定を実証的基盤の上に置く経営論を確立した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"スタートアップ成長論","era_start":2010,"schumpeter_layer":"ミクロ","innovation_type":"データ駆動イノベーション","cognitive_mechanism":"定量的フィードバックによる高速学習ループ","key_researchers":["Jeff Huber","DJ Patil","Hilary Mason"],"key_works":["Data Science for Startups (2018)","Building a Data-Driven Company (2016)"],"keywords_ja":"データ駆動,A/Bテスト,コホート分析,LTV,スタートアップ分析","keywords_en":"data-driven,A/B testing,cohort analysis,LTV,startup analytics"},
  {"id":"inno_ent_334","name_ja":"アントレプレナーシップとAI活用","name_en":"AI-Enabled Entrepreneurship","definition":"人工知能ツールを活用した起業プロセスの変革研究。GPT等の生成AIによるビジネスプラン自動生成、コード生成（GitHub Copilot）による技術的参入障壁低下、AIによる市場調査・競合分析自動化が研究対象。「1人企業（solo company）」の可能性、AIとVC意思決定の交差、AI起業家の出現（自律的エージェントによる事業運営）も近年の研究テーマ。","impact_summary":"AIが起業家精神の民主化を加速し、参入障壁・チームサイズ・資本要件を根本的に変える可能性を示した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"技術起業家論","era_start":2022,"schumpeter_layer":"ミクロ","innovation_type":"AI活用イノベーション","cognitive_mechanism":"AI補完による起業家的能力の増幅","key_researchers":["Sam Altman","Ethan Mollick","Emad Mostaque"],"key_works":["Scaling Solo with AI (2023)","The New Anatomy of a Startup (2023)"],"keywords_ja":"AI起業家精神,生成AI,コード生成,ソロカンパニー,参入障壁低下","keywords_en":"AI entrepreneurship,generative AI,code generation,solo company,barrier reduction"},
  {"id":"inno_ent_335","name_ja":"起業家精神とダイバーシティ","name_en":"Entrepreneurship and Diversity","definition":"人種・民族・ジェンダー・年齢・障害等の多様性が起業エコシステムの包摂性・パフォーマンスに与える影響の研究。多様なチームがより広い市場機会を認識し、グループシンクを避ける効果が実証される。一方でHomophily（同質性志向）がVCの投資先選択を歪めるという批判も研究されている。DEI（多様性・公平性・包摂性）方針の起業支援への組み込みが政策課題化している。","impact_summary":"起業エコシステムの多様性が競争力と包摂性を高めることを実証し、DEI政策の起業家支援への統合を促進した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"フェミニスト起業家論","era_start":2015,"schumpeter_layer":"メゾ","innovation_type":"社会・文化イノベーション","cognitive_mechanism":"認知的多様性と機会認識の多角化","key_researchers":["Alison Wood Brooks","Malin Malmstrom","Diversity VC team"],"key_works":["Investors Prefer Entrepreneurial Ventures (2014)","The Diversity Bonus (2017)"],"keywords_ja":"ダイバーシティ,DEI,多様性,Homophily,包摂的エコシステム","keywords_en":"diversity,DEI,homophily,inclusive ecosystem,diverse teams"},
  {"id":"inno_ent_336","name_ja":"起業家精神とウェルネス・マインドフルネス","name_en":"Entrepreneurial Wellness and Mindfulness","definition":"起業家の心身健康維持と持続可能なパフォーマンスに関する実践的研究。「Hustle Culture（ハッスル文化）」批判から、レジリエントな経営のためのマインドフルネス実践、睡眠・運動・瞑想の起業成果への影響が研究される。Y Combinator創業者Paul GrahamやArianna Huffingtonのウェルネス重視メッセージが業界規範を変えつつある。","impact_summary":"持続可能な起業家精神のための健康・ウェルネスの重要性を主流化し、スタートアップ支援にメンタルヘルス要素を組み込む流れを作った。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"行動的起業家論","era_start":2014,"schumpeter_layer":"ミクロ","innovation_type":"ウェルネスイノベーション","cognitive_mechanism":"心身健康と認知的パフォーマンスの相互強化","key_researchers":["Michael Freeman","Arianna Huffington","Rasmus Hougaard"],"key_works":["Thrive (2014)","The Mind of the Leader (2018)"],"keywords_ja":"起業家ウェルネス,マインドフルネス,Hustle Culture批判,精神健康","keywords_en":"entrepreneurial wellness,mindfulness,hustle culture critique,mental health"},
  {"id":"inno_ent_337","name_ja":"Stripe Atlasと起業の民主化","name_en":"Stripe Atlas and Entrepreneurship Democratization","definition":"StripeのAtlasプログラム（2016年〜）による海外からの米国Delaware法人設立の簡略化が起業家精神のグローバル民主化に与えた影響の研究。ナイジェリア、インドネシア、ベトナム等の起業家がシリコンバレーのVC・銀行・ツールエコシステムにアクセスできるようにした。国籍・地理的障壁を低下させる「インターネット上の起業インフラ」概念が研究対象。","impact_summary":"法的・金融的インフラのデジタル化が起業家精神の地理的民主化を推進することを実証した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"プラットフォーム論","era_start":2016,"schumpeter_layer":"メゾ","innovation_type":"インフラ・民主化イノベーション","cognitive_mechanism":"アクセス障壁の制度的除去と新興市場起業家の活性化","key_researchers":["Patrick Collison","Stripe team","SVIX research"],"key_works":["Stripe Atlas Reports (annual)","Internet Economy Reports (2020)"],"keywords_ja":"Stripe Atlas,起業民主化,Delaware法人,グローバル起業家","keywords_en":"Stripe Atlas,entrepreneurship democratization,Delaware company,global founders"},
  {"id":"inno_ent_338","name_ja":"起業家精神の進化適応的起源","name_en":"Evolutionary Origins of Entrepreneurship","definition":"起業家的行動（探索・冒険・資源獲得）が人類の進化的適応として生じたとする研究。Hunter-gatherer起業家精神の比喩、ADHD・ハイパーフォーカス・衝動性等の神経多様性と起業家的気質の相関（Antshel 2017、Wiklund et al. 2018）、テストステロンとリスク選好の関係が研究される。起業家的気質が一定割合で集団内に維持される進化的均衡も論じられる。","impact_summary":"起業家精神の生物学的・進化的基盤を探求し、神経多様性と起業家精神の関係研究を切り開いた。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"進化心理学的起業家論","era_start":2018,"schumpeter_layer":"ミクロ","innovation_type":"研究方法論イノベーション","cognitive_mechanism":"神経多様性と探索的リスク選好の相互関係","key_researchers":["Johan Wiklund","Holger Patzelt","Karl Wennberg"],"key_works":["Entrepreneurship and Psychological Disorders (2018)","ADHD and Entrepreneurial Success (2017)"],"keywords_ja":"起業家精神,進化,神経多様性,ADHD,生物学","keywords_en":"entrepreneurship,evolution,neurodiversity,ADHD,biology"},
  {"id":"inno_ent_339","name_ja":"スタートアップのIPO戦略","name_en":"Startup IPO Strategy","definition":"スタートアップが株式公開（IPO）を通じて公開市場に移行する際の戦略・タイミング・プロセスの研究。Under-pricing phenomenon（IPO初値割引）の測定と説明（情報非対称性、投資家需要シグナリング）、Lock-up期間設計、デュアルクラス株式（創業者議決権保護）の功罪が研究される。Spotify、Slack、Palantirが採用したDirect Listing（幹事証券不要の直接上場）も近年の研究対象。","impact_summary":"スタートアップのExitルートとしてのIPO制度設計を理論化し、創業者の長期コントロール維持と資本市場アクセスの両立策を研究した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"コーポレートファイナンス論","era_start":1990,"schumpeter_layer":"ミクロ","innovation_type":"金融・資本市場イノベーション","cognitive_mechanism":"上場タイミングと情報開示の戦略的管理","key_researchers":["Jay Ritter","Tim Loughran","Alexander Ljungqvist"],"key_works":["Initial Public Offerings (2002)","IPO Pricing (2009)"],"keywords_ja":"IPO,スタートアップ上場,Direct Listing,デュアルクラス株,アンダープライシング","keywords_en":"IPO,startup listing,direct listing,dual-class shares,underpricing"},
  {"id":"inno_ent_340","name_ja":"M&AによるスタートアップExit","name_en":"M&A Exit Strategy for Startups","definition":"起業家がVCからのリターン実現とスケールアップのためにM&Aによるexitを選択するプロセスの研究。Acqui-hire（技術・人材獲得目的のM&A）、GAFA等の大企業によるスタートアップ買収の動機（キル・ゾーン戦略vs真の補完戦略）、buy-out条件交渉（earnout、競業避止）が研究される。欧州のMnAエコシステムが米国と比較して浅く多くのスタートアップが米国大企業に買収される「exit brain drain」も問題化している。","impact_summary":"M&AをVCエコシステムの流動性メカニズムとして位置づけ、exitルートの多様化と大企業のイノベーション獲得論理を整理した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"コーポレートファイナンス論","era_start":1995,"schumpeter_layer":"メゾ","innovation_type":"M&A・exit戦略イノベーション","cognitive_mechanism":"exit価値最大化と企業文化適合の均衡","key_researchers":["Reena Aggarwal","Nikhil Varaiya","Joseph Noel"],"key_works":["Mergers and Acquisitions (2002)","The M&A Process (2018)"],"keywords_ja":"M&A,スタートアップexit,acqui-hire,kill zone,earnout","keywords_en":"M&A,startup exit,acqui-hire,kill zone,earnout"},
  {"id":"inno_ent_341","name_ja":"起業家精神のジェンダー化された意味","name_en":"Gendered Meanings of Entrepreneurship","definition":"起業家精神の概念的枠組み自体が男性的価値観（リスクテイキング、競争的攻撃性、独立心）に偏っているという批判的フェミニスト研究。Ahl（2006）はGEMや学術論文が「女性起業家の問題化」を再生産しているとした。女性特有の動機（ケアワークとの両立、コミュニティへの貢献）が従来の枠組みで捉えられないことが指摘される。","impact_summary":"起業家研究の認識論的偏向を批判し、多様な起業形態と動機を包摂する新しい枠組みの開発を促した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"フェミニスト起業家論","era_start":2006,"schumpeter_layer":"ミクロ","innovation_type":"批判的・認識論的イノベーション","cognitive_mechanism":"ジェンダー化された起業概念の内面化と抵抗","key_researchers":["Helene Ahl","Denise Fletcher","Sara Carter"],"key_works":["Why Research on Women Entrepreneurs Needs New Directions (2006)","Women's Entrepreneurship in Europe (2019)"],"keywords_ja":"起業家精神のジェンダー化,フェミニスト批判,女性起業家研究","keywords_en":"gendered entrepreneurship,feminist critique,women entrepreneurship research"},
  {"id":"inno_ent_342","name_ja":"インドのUPI決済と起業家精神","name_en":"India UPI and Fintech Entrepreneurship","definition":"インド政府主導のUPI（Unified Payments Interface）デジタル決済インフラ（2016年〜）が生み出したフィンテック起業家精神の研究。PhonePe、Paytm、Google Pay等がUPI上に構築された事例。公共デジタルインフラ（DPI）が民間スタートアップの参入障壁を下げ、金融包摂（13億人への決済アクセス）を実現するモデルとして世界から注目される。","impact_summary":"政府デジタルインフラが民間起業家精神の触媒となる「DPI起業家モデル」を実証し、グローバルサウスのインフラ主導起業政策の参照例となった。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"制度的起業家論","era_start":2016,"schumpeter_layer":"メゾ","innovation_type":"デジタルインフライノベーション","cognitive_mechanism":"オープンインフラとスタートアップ参入の連鎖","key_researchers":["Nandan Nilekani","iSPIRT team","Arvind Narayanan"],"key_works":["Rebooting India (2015)","India DPI Stack Report (2022)"],"keywords_ja":"UPI,デジタルインフラ,DPI,インドフィンテック,PhonePe","keywords_en":"UPI,digital public infrastructure,DPI,India fintech,PhonePe"},
  {"id":"inno_ent_343","name_ja":"社会起業のハイブリッド組織論","name_en":"Hybrid Organization Theory in Social Entrepreneurship","definition":"営利と非営利の論理を同時に追求するハイブリッド組織（社会的企業、BCorp、CIC等）の経営・ガバナンス・アイデンティティ研究。Battilana & Lee（2014）は「ミッション-マーケット緊張」の管理メカニズムを分析した。ミッション・ドリフト（財務的成功に伴う社会的使命の薄化）防止のガバナンス設計が主要テーマ。","impact_summary":"ハイブリッド組織の運営論理と持続可能性条件を理論化し、社会的企業の実践的ガバナンス設計に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"社会的起業家論","era_start":2014,"schumpeter_layer":"メゾ","innovation_type":"組織・ガバナンスイノベーション","cognitive_mechanism":"複数の制度的論理の同時管理","key_researchers":["Julie Battilana","Matthew Lee","Marya Besharov"],"key_works":["Advancing Research on Hybrid Organizing (2014)","The Legitimacy of Hybrid Organizations (2019)"],"keywords_ja":"ハイブリッド組織,社会的企業,ミッションドリフト,BCorp,制度的論理","keywords_en":"hybrid organization,social enterprise,mission drift,BCorp,institutional logics"},
  {"id":"inno_ent_344","name_ja":"スタートアップの国際会計基準適用","name_en":"International Accounting Standards for Startups","definition":"スタートアップが成長とともに直面する財務管理・会計基準適用の課題研究。初期のMFR（Minimum Financial Reporting）からIFRS/US GAAP適用への移行コスト、ストックオプション費用計上（ASC 718、IFRS 2）、収益認識（ASC 606、IFRS 15）の複雑さがVC・IPO準備段階で問題化する。CFO採用タイミングと財務ガバナンス強化の最適化が研究される。","impact_summary":"スタートアップの財務ガバナンス成熟度と資本調達・上場準備の関係を整理し、スタートアップCFO職の重要性を確立した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"コーポレートファイナンス論","era_start":2005,"schumpeter_layer":"ミクロ","innovation_type":"財務・ガバナンスイノベーション","cognitive_mechanism":"財務透明性と投資家信頼の構築","key_researchers":["Brad Feld","Jason Mendelson","David Currie"],"key_works":["Venture Deals (2011)","Finance for Startups (2020)"],"keywords_ja":"スタートアップ財務,IFRS,ストックオプション,CFO,会計基準","keywords_en":"startup finance,IFRS,stock options,CFO,accounting standards"},
  {"id":"inno_ent_345","name_ja":"起業家精神とウーバー化","name_en":"Uberization and Platform Entrepreneurship","definition":"Uberが開拓した「既存資産を活用したオンデマンドサービス」モデルを様々な産業（ホテル・物流・医療等）に適用する「ウーバー化（Uberization）」現象と起業家精神の研究。資産軽量型ビジネスモデル、ダイナミックプライシング、ギグワーカー経済がもたらす産業再編と起業機会が分析される。各国での規制摩擦（タクシー規制、労働法等）との関係も重要テーマ。","impact_summary":"資産軽量型プラットフォームモデルの産業横断的展開パターンを記述し、レガシー産業への起業的侵入の論理を整理した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"プラットフォーム論","era_start":2014,"schumpeter_layer":"メゾ","innovation_type":"プラットフォームイノベーション","cognitive_mechanism":"既存資産の再活用と効率性ギャップの認識","key_researchers":["Arun Sundararajan","Robin Chase","Tom Goodwin"],"key_works":["The Sharing Economy (2016)","Peers Inc (2015)"],"keywords_ja":"ウーバー化,シェアリングエコノミー,資産軽量,オンデマンド,ギグ","keywords_en":"uberization,sharing economy,asset-light,on-demand,gig"},
  {"id":"inno_ent_346","name_ja":"起業家精神と科学技術政策の接点","name_en":"Entrepreneurship and Science Technology Policy Interface","definition":"科学技術政策（研究費配分、産学連携政策、規制サンドボックス）と起業家精神の関係研究。小さな政府モデル（米国）対産業政策的モデル（韓国・中国・フィンランド）の比較、SBIRプログラム（米国中小企業イノベーション研究補助金）の効果評価、EIC（欧州イノベーション評議会）のディープテック支援が主要ケース。","impact_summary":"科学技術政策を起業家精神の促進・抑制要因として体系的に分析し、政策統合の理論基盤を提供した。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"政策的起業家論","era_start":2000,"schumpeter_layer":"マクロ","innovation_type":"政策・科学イノベーション","cognitive_mechanism":"政策インセンティブと研究者起業動機の連動","key_researchers":["Josh Lerner","Albert Link","John Scott"],"key_works":["The SBIR Program (2005)","Public Investment, Industrial Policy (2012)"],"keywords_ja":"科学技術政策,SBIR,EIC,産業政策,研究者起業","keywords_en":"science technology policy,SBIR,EIC,industrial policy,researcher entrepreneurship"},
  {"id":"inno_ent_347","name_ja":"起業家精神教育のインパクト投資家育成","name_en":"Impact Investor Education in Entrepreneurship","definition":"インパクト投資家を育成するための教育プログラムと、起業家・投資家双方への「インパクトマインドセット」浸透プロセスの研究。EVPA（European Venture Philanthropy Association）、Toniic、RS Group等が実践コミュニティを形成。IMP（Impact Management Project）フレームワークによるインパクト評価のスタンダード化が教育基盤を整備している。","impact_summary":"インパクト投資家の育成と知識標準化により、インパクトエコシステムの資金調達側の専門性を高めた。","subfield":"entrepreneurship_venture","category":"B_systems","school_of_thought":"社会的起業家論","era_start":2010,"schumpeter_layer":"メゾ","innovation_type":"教育・投資イノベーション","cognitive_mechanism":"デュアルリターン思考と測定能力の習得","key_researchers":["Jed Emerson","Clara Barby","IMP project team"],"key_works":["Impact Measurement in Practice (2018)","A Framework for Impact (IMP 2019)"],"keywords_ja":"インパクト投資教育,IMP,EVPA,インパクト測定,デュアルリターン","keywords_en":"impact investor education,IMP,EVPA,impact measurement,dual return"},
  {"id":"inno_ent_348","name_ja":"スタートアップのカスタマーサクセス","name_en":"Customer Success in Startups","definition":"SaaSスタートアップにおける顧客の成功支援（Customer Success）組織の構築と、それによる解約率低下・アップセル促進・NPS向上の研究。Lincoln Murphy等が体系化したCS哲学：「顧客が望む成果を達成し、それを続けられるようにする」。NRR（Net Revenue Retention）100%超の達成が持続成長の鍵として研究される。CS組織設計・タッチモデル（ハイタッチ/テックタッチ）が主要テーマ。","impact_summary":"SaaSビジネスにおけるカスタマーサクセスを独立した経営機能として確立し、subscription経済の持続成長論理を整備した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"スタートアップ成長論","era_start":2013,"schumpeter_layer":"ミクロ","innovation_type":"顧客成功イノベーション","cognitive_mechanism":"顧客価値実現と継続利用動機の連鎖","key_researchers":["Lincoln Murphy","Nick Mehta","Dan Steinman"],"key_works":["Customer Success (2016)","The Customer Success Economy (2020)"],"keywords_ja":"カスタマーサクセス,SaaS,NRR,解約率,アップセル","keywords_en":"customer success,SaaS,NRR,churn rate,upsell"},
  {"id":"inno_ent_349","name_ja":"起業家精神と宗教・信仰","name_en":"Entrepreneurship and Religion/Faith","definition":"宗教的信仰が起業行動・倫理・組織運営に与える影響の研究。プロテスタント倫理とWeberian資本主義論の延長として、現代のキリスト教ビジネスネットワーク（Full Gospel Business Men等）、イスラム的ビジネス倫理、ユダヤ的商業文化が比較研究される。宗教的信仰が不確実性耐性・リスク管理・倫理的制約に与える影響が定量的に研究される。","impact_summary":"宗教・信仰が起業行動に与える影響を実証的に記述し、文化的・制度的多様性のある起業家研究に貢献した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"文化的起業家論","era_start":2007,"schumpeter_layer":"ミクロ","innovation_type":"文化・宗教的イノベーション","cognitive_mechanism":"宗教的動機と倫理的制約の起業行動への影響","key_researchers":["David Miller","Bruce Avolio","Edward Hess"],"key_works":["God at Work (2007)","Leading with Values (2016)"],"keywords_ja":"起業家精神,宗教,信仰,プロテスタント倫理,イスラム起業","keywords_en":"entrepreneurship,religion,faith,Protestant ethic,Islamic entrepreneurship"},
  {"id":"inno_ent_350","name_ja":"起業家精神の「Hustle Culture」批判","name_en":"Critique of Hustle Culture in Entrepreneurship","definition":"「常に働け、休むな」を賞賛するHustle Cultureへの批判的研究。Cal Newport、Alex Soojung-Kim Pang等が「deep work」「rest」の重要性を主張。Arianna Huffingtonの「Thrive」（燃え尽き症候群体験後）、Reid Hoffmanの「Blitzscaling」への反論として登場したSlow Startup運動が研究される。長時間労働と生産性・創造性の逆U字関係も実証されている。","impact_summary":"持続可能な起業家精神の条件を問い直し、スタートアップ文化のウェルビーイング重視への転換議論を推進した。","subfield":"entrepreneurship_venture","category":"A_foundations","school_of_thought":"批判的起業家論","era_start":2018,"schumpeter_layer":"ミクロ","innovation_type":"文化・価値観イノベーション","cognitive_mechanism":"長時間労働への認知的反省と休息による回復","key_researchers":["Arianna Huffington","Cal Newport","Alex Pang"],"key_works":["Thrive (2014)","Rest (2016)","Deep Work (2016)"],"keywords_ja":"Hustle Culture批判,ウェルビーイング,Deep Work,Slow Startup,持続可能起業","keywords_en":"hustle culture critique,well-being,deep work,slow startup,sustainable entrepreneurship"},
]
conn = sqlite3.connect(DB)
